__kernel void extract_kernel(long d_Ne, __global float *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global float *d_I,
                             __global float *d_sums,
                             __global float *d_sums2) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        float v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global float *d_sums,
                            __global float *d_sums2,
                            int d_blocks) {
    (void)d_Ne;
    (void)d_blocks;

    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);
    const int bx = (int)get_group_id(0);

    if (lid == 0) {
        long start = (long)bx * (long)lsize;
        long end = start + (long)lsize;
        if (end > d_no) end = d_no;

        float sum = 0.0f;
        float sum2 = 0.0f;

        for (long i = start; i < end; i++) {
            long idx = i * (long)d_mul;
            sum += d_sums[idx];
            sum2 += d_sums2[idx];
        }

        long out_idx = (long)bx * (long)d_mul * (long)lsize;
        d_sums[out_idx] = sum;
        d_sums2[out_idx] = sum2;
    }
}

__kernel void srad_kernel(float lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global float *d_dN,
                          __global float *d_dS,
                          __global float *d_dW,
                          __global float *d_dE,
                          float q0sqr,
                          __global float *d_c,
                          __global float *d_I) {
    (void)lambda;
    (void)Nr;

    long ei = (long)get_global_id(0);
    if (ei >= Ne) return;

    int row = (int)(ei / (long)Nc);
    int col = (int)(ei % (long)Nc);

    float Jc = d_I[ei];

    float dN = d_I[(long)iN[row] * (long)Nc + (long)col] - Jc;
    float dS = d_I[(long)iS[row] * (long)Nc + (long)col] - Jc;
    float dW = d_I[(long)row * (long)Nc + (long)jW[col]] - Jc;
    float dE = d_I[(long)row * (long)Nc + (long)jE[col]] - Jc;

    float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
    float L = (dN + dS + dW + dE) / Jc;

    float num = (0.5f * G2) - (0.0625f * (L * L));
    float den = 1.0f + (0.25f * L);
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c = 1.0f / (1.0f + den);

    if (c < 0.0f) c = 0.0f;
    else if (c > 1.0f) c = 1.0f;

    d_dN[ei] = dN;
    d_dS[ei] = dS;
    d_dW[ei] = dW;
    d_dE[ei] = dE;
    d_c[ei] = c;
}

__kernel void srad2_kernel(float lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global float *d_dN,
                           __global float *d_dS,
                           __global float *d_dW,
                           __global float *d_dE,
                           __global float *d_c,
                           __global float *d_I) {
    (void)Nr;
    (void)iN;
    (void)jW;

    long ei = (long)get_global_id(0);
    if (ei >= Ne) return;

    int row = (int)(ei / (long)Nc);
    int col = (int)(ei % (long)Nc);

    float cN = d_c[ei];
    float cS = d_c[(long)iS[row] * (long)Nc + (long)col];
    float cW = d_c[ei];
    float cE = d_c[(long)row * (long)Nc + (long)jE[col]];

    float D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
    d_I[ei] = d_I[ei] + 0.25f * lambda * D;
}

__kernel void compress_kernel(long d_Ne, __global float *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
